def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    prs = Presentation(modified_ppt_path)
    slide = None
    # python-pptx Slide objects don't expose a slide_number property; use index (1-based)
    for idx, s in enumerate(prs.slides, start=1):
        if idx == 19:
            slide = s
            break
    if not slide:
        return ("Slide 19 not found.", 0)
    # Find the word 'HSC' in any shape and check if it has a hyperlink
    found = False
    for shape in slide.shapes:
        if not shape.has_text_frame:
            continue
        text_frame = shape.text_frame
        for paragraph in text_frame.paragraphs:
            text = paragraph.text
            if 'HSC' in text:
                # Check if a run with 'HSC' has a hyperlink
                for run in paragraph.runs:
                    # Detect hyperlink presence without dereferencing relationships (avoids KeyError on empty rIds)
                    if 'HSC' in run.text:
                        hyperlink = getattr(run, 'hyperlink', None)
                        if hyperlink is None:
                            continue
                        hlink_click = getattr(hyperlink, '_hlinkClick', None)
                        # Presence of a:hlinkClick indicates a hyperlink (external or internal)
                        if hlink_click is not None:
                            found = True
                            break
            if found:
                break
        if found:
            break
    if found:
        return ("Hyperlink present on 'HSC' in slide 19.", 1)
    else:
        return ("No hyperlink found on 'HSC' in slide 19.", 0)

def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    prs = Presentation(modified_ppt_path)
    slide_1 = None
    slide_19 = None
    # Find slide 1 and slide 19 using 1-based index
    for idx, s in enumerate(prs.slides, start=1):
        if idx == 1:
            slide_1 = s
        if idx == 19:
            slide_19 = s
    if slide_1 is None or slide_19 is None:
        return ("Could not find slide 1 or slide 19.", 0)

    hsc_found = False
    hyperlink_found = False

    for shape in slide_19.shapes:
        if not shape.has_text_frame:
            continue
        text_frame = shape.text_frame
        for paragraph in text_frame.paragraphs:
            for run in paragraph.runs:
                if 'HSC' not in run.text:
                    continue
                hsc_found = True

                # Check for hyperlink using multiple methods
                hyperlink = getattr(run, 'hyperlink', None)
                if hyperlink is not None:
                    hyperlink_found = True

                    hlink = getattr(hyperlink, '_hlinkClick', None)
                    if hlink is not None:
                        # 1) If this is a "jump to first slide" action, accept immediately
                        action = None
                        try:
                            action = getattr(hlink, 'action', None) or hlink.get('action')
                        except Exception:
                            action = None
                        if action and isinstance(action, str) and 'firstslide' in action.lower():
                            return ("Hyperlink on 'HSC' correctly points to slide 1.", 1)

                        # 2) Otherwise, try resolving target_slide safely and compare to slide_1
                        try:
                            target_slide = getattr(hyperlink, 'target_slide', None)
                            # Some versions expose target_slide as a property; if callable, call it
                            if callable(target_slide):
                                target_slide = target_slide()
                        except Exception:
                            target_slide = None

                        if target_slide is not None:
                            # Compare by object, and fall back to partname comparison
                            same_slide = False
                            try:
                                same_slide = target_slide is slide_1 or target_slide == slide_1
                            except Exception:
                                same_slide = False
                            if not same_slide:
                                try:
                                    same_slide = (
                                        getattr(getattr(target_slide, 'part', None), 'partname', None)
                                        == getattr(getattr(slide_1, 'part', None), 'partname', None)
                                    )
                                except Exception:
                                    same_slide = False
                            if same_slide:
                                return ("Hyperlink on 'HSC' correctly points to slide 1.", 1)
                            else:
                                return ("Hyperlink on 'HSC' does not point to slide 1.", 0)
                        else:
                            # Hyperlink exists but target cannot be determined
                            return ("Hyperlink on 'HSC' does not point to slide 1.", 0)
                    else:
                        # Hyperlink object exists but no _hlinkClick - still a hyperlink
                        return ("Hyperlink on 'HSC' does not point to slide 1.", 0)

    if hsc_found and hyperlink_found:
        return ("Hyperlink on 'HSC' does not point to slide 1.", 0)
    elif hsc_found:
        return ("No hyperlink found on 'HSC' in slide 19.", 0)
    else:
        return ("Text 'HSC' not found in slide 19.", 0)

